/* Element */
h1 { color: red; }

/* Class */
.card { border: 1px solid #ccc; }

/* ID */
#header { background: black; }

/* Attribute */
[type="text"] { border-color: blue; }
input[required] { border-color: red; }

/* Descendant */
div p { color: gray; }

/* Child */
ul > li { list-style: none; }

/* Adjacent sibling */
h2 + p { margin-top: 0; }

/* Pseudo-class */
a:hover { color: blue; }
a:focus { outline: 2px solid; }
tr:nth-child(even) { background: #f5f5f5; }
input:valid { border-color: green; }

/* Pseudo-element */
::before { content: "\2192"; }
::after { content: ""; }
::first-line { font-weight: bold; }

/* Box model: content -> padding -> border -> margin */
.box {
  width: 300px;
  height: 200px;
  padding: 20px;        /* inside border */
  border: 2px solid black;
  margin: 10px;          /* outside border */

  /* Box-sizing controls how width/height is calculated */
  box-sizing: border-box;  /* width includes padding + border */
  /* box-sizing: content-box; (default) width = content only */
}

/* Shorthand: top right bottom left */
padding: 10px 20px 10px 20px;
padding: 10px 20px; /* top/bottom, left/right */
margin: 0 auto;     /* center horizontally */

.container {
  display: flex;
  flex-direction: row;        /* row (default), column, row-reverse */
  flex-wrap: wrap;             /* nowrap (default), wrap */
  justify-content: center;     /* flex-start, center, space-between, space-around */
  align-items: center;         /* stretch, center, flex-start */
  align-content: center;       /* for multi-line wrapping */
  gap: 16px;                   /* spacing between items */
}

.item {
  flex: 1;                     /* grow equally */
  flex: 0 0 200px;             /* grow, shrink, basis */
  align-self: flex-start;      /* override align-items */
  order: -1;                   /* reorder items */
}

/* Common patterns */
.centered {
  display: flex;
  justify-content: center;
  align-items: center;
}

.nav {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.grid-3 {
  display: flex;
  flex-wrap: wrap;
  gap: 20px;
}
.grid-3 > * {
  flex: 1 1 30%;
  min-width: 250px;
}

.container {
  display: grid;
  grid-template-columns: 1fr 2fr 1fr;   /* 3 columns */
  grid-template-columns: repeat(3, 1fr); /* 3 equal columns */
  grid-template-columns: 200px 1fr;      /* fixed + fluid */
  grid-template-rows: auto 1fr auto;
  gap: 16px;

  /* Grid areas */
  grid-template-areas:
    "header header header"
    "sidebar main aside"
    "footer footer footer";
}

.header { grid-area: header; }
.sidebar { grid-area: sidebar; }
.main { grid-area: main; }

/* Item placement */
.item {
  grid-column: 1 / 3;        /* span columns 1-2 */
  grid-column: span 2;       /* span 2 columns */
  grid-row: 1 / 3;            /* span rows */
}

/* Auto-fit for responsive */
.responsive-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
  gap: 20px;
}

/* Mobile-first approach (min-width) */
/* Base styles: mobile */
.grid {
  display: grid;
  grid-template-columns: 1fr;
}

/* Tablet */
@media (min-width: 768px) {
  .grid {
    grid-template-columns: 1fr 1fr;
  }
}

/* Desktop */
@media (min-width: 1024px) {
  .grid {
    grid-template-columns: 1fr 1fr 1fr;
  }
}

/* Large desktop */
@media (min-width: 1440px) {
  .container { max-width: 1400px; margin: 0 auto; }
}

/* Dark mode */
@media (prefers-color-scheme: dark) {
  :root {
    --bg: #111;
    --text: #eee;
  }
}

/* Print */
@media print {
  nav, footer { display: none; }
}

/* Reduced motion */
@media (prefers-reduced-motion: reduce) {
  * { animation: none !important; }
}

/* Color formats */
color: red;               /* named */
color: #ff0000;           /* hex */
color: #f00;              /* short hex */
color: rgba(255,0,0,0.5);  /* rgb with alpha */
color: hsl(0, 100%, 50%);  /* hue, saturation, lightness */
color: hsla(0, 100%, 50%, 0.5);

/* Gradients */
background: linear-gradient(to right, red, blue);
background: linear-gradient(45deg, #f00, #00f);
background: radial-gradient(circle, white, black);
background: conic-gradient(red, yellow, green);

body {
  font-family: 'Inter', system-ui, -apple-system, sans-serif;
  font-size: 16px;
  font-weight: 400;
  line-height: 1.6;
  letter-spacing: 0.02em;
  text-align: left;
}

h1 {
  font-family: 'Poppins', sans-serif;
  font-weight: 700;
  font-size: clamp(2rem, 5vw, 3.5rem);
  line-height: 1.2;
}

/* Text properties */
text-decoration: underline;
text-transform: uppercase;
text-shadow: 2px 2px 4px rgba(0,0,0,0.3);
white-space: nowrap;
word-break: break-word;
text-overflow: ellipsis;
overflow: hidden;  /* for ellipsis */
-webkit-line-clamp: 3;  /* limit to 3 lines */

.button {
  background: blue;
  color: white;
  transition: all 0.3s ease;
  /* transition: property duration timing-function delay */
}

.button:hover {
  background: darkblue;
  transform: scale(1.05);
}

.card {
  transition: transform 0.3s ease, box-shadow 0.3s ease;
}
.card:hover {
  transform: translateY(-4px);
  box-shadow: 0 10px 30px rgba(0,0,0,0.15);
}

/* Timing functions */
ease | linear | ease-in | ease-out | ease-in-out
cubic-bezier(0.4, 0, 0.2, 1)

@keyframes fadeIn {
  from { opacity: 0; transform: translateY(10px); }
  to { opacity: 1; transform: translateY(0); }
}

@keyframes spin {
  to { transform: rotate(360deg); }
}

@keyframes pulse {
  0%, 100% { transform: scale(1); }
  50% { transform: scale(1.05); }
}

.element {
  animation: fadeIn 0.5s ease forwards;
  animation: spin 1s linear infinite;
  animation: pulse 2s ease infinite;
  /* animation: name duration timing-function delay iteration-count direction */
}

/* Animation properties */
.animated {
  animation-name: fadeIn;
  animation-duration: 0.5s;
  animation-timing-function: ease-out;
  animation-delay: 0.2s;
  animation-iteration-count: 1;
  animation-direction: normal;
  animation-fill-mode: forwards;
}

/* prefers-reduced-motion */
@media (prefers-reduced-motion: reduce) {
  *, *::before, *::after {
    animation-duration: 0.01ms !important;
    transition-duration: 0.01ms !important;
  }
}

.scroll-box {
  overflow: auto;         /* scroll when needed */
  overflow: scroll;       /* always show scrollbar */
  overflow: hidden;       /* clip content */
  overflow-x: auto;       /* horizontal only */
  overflow-y: scroll;     /* vertical always */

  /* text overflow */
  text-overflow: ellipsis;
  white-space: nowrap;
}

/* Z-index stacking */
.modal { z-index: 1000; }
.overlay { z-index: 999; }
.dropdown { z-index: 100; }

/* Z-index only works on positioned elements */
z-index: auto;   /* default, follows parent */
z-index: 1;      /* on top of siblings */

:root {
  --primary: #7c3aed;
  --primary-light: #a78bfa;
  --text: #171717;
  --bg: #ffffff;
  --radius: 8px;
  --shadow: 0 2px 8px rgba(0,0,0,0.1);
  --font-main: 'Inter', sans-serif;
}

[data-theme="dark"] {
  --text: #ededed;
  --bg: #0a0a0a;
}

.button {
  background: var(--primary);
  border-radius: var(--radius);
  box-shadow: var(--shadow);
  font-family: var(--font-main);
  color: white;
  padding: 0.5em 1em;
}

/* calc, min, max, clamp */
.responsive {
  width: calc(100% - 40px);
  font-size: max(1rem, 2.5vw);
  padding: clamp(1rem, 3vw, 2rem);
}

/* Container queries */
@container (min-width: 400px) {
  .card { display: grid; grid-template-columns: 1fr 1fr; }
}

/* Nesting (CSS Nesting 1) */
.card {
  background: white;

  & h2 { color: blue; }
  & .body { padding: 1rem; }
  &:hover { box-shadow: 0 4px 8px rgba(0,0,0,0.2); }
}

/* has() selector */
.card:has(img) {
  grid-template-rows: auto 1fr;
}
.form:has(:invalid) .submit { opacity: 0.5; }

/* Scroll snap */
.gallery {
  display: flex;
  overflow-x: auto;
  scroll-snap-type: x mandatory;
}
.gallery img { scroll-snap-align: center; }

// Variables
$primary: #7c3aed;
$breakpoint-md: 768px;

// Nesting
nav {
  ul { display: flex; }
  li { list-style: none; }
  a { color: $primary; }
}

// Mixins
@mixin flex-center {
  display: flex;
  justify-content: center;
  align-items: center;
}

.modal { @include flex-center; }

// Extend
%btn-base {
  padding: 0.5em 1em;
  border-radius: 4px;
}
.btn-primary { @extend %btn-base; background: $primary; }

// Functions
@function rem($px) {
  @return ($px / 16px) * 1rem;
}
h1 { font-size: rem(32px); }
